    if (a > b) best = r;
    else if (a === b) {
      const ae = new Date(r.current_period_end || 0).getTime();
      const be = new Date(best.current_period_end || 0).getTime();
      if (ae > be) best = r;
    }
  }
}

const plan_id = best?.plan_id ?? null;
const sub_status = best?.status ?? null;

const usage_period_start = best?.current_period_start ?? null;
const usage_period_end = best?.current_period_end ?? null;

return [{
