const current = $input.first() || { json: {} };
const j = current.json || {};

function safePart(value, fallback = 'na') {
  const out = String(value ?? '').trim().replace(/[^a-zA-Z0-9._-]+/g, '-').replace(/-+/g, '-').replace(/^-|-$/g, '');
  return out || fallback;
}

function pickExt(mime, contentType) {
  const m = String(mime || '').toLowerCase();
  const ct = String(contentType || '').toLowerCase();

  if (m === 'image/jpeg') return 'jpg';
  if (m === 'image/png') return 'png';
  if (m === 'image/webp') return 'webp';
  if (m === 'audio/ogg') return 'ogg';
  if (m === 'audio/mpeg') return 'mp3';
  if (m === 'audio/mp4') return 'm4a';
  if (m === 'video/mp4') return 'mp4';
  if (m.startsWith('image/')) return 'jpg';
  if (m.startsWith('audio/')) return 'ogg';
  if (m.startsWith('video/')) return 'mp4';

  if (ct === 'image') return 'jpg';
  if (ct === 'audio') return 'ogg';
  if (ct === 'video') return 'mp4';

  return 'bin';
}

const media = j.media || {};
const ext = pickExt(media.mime_type, j.content_type);
const bucket = 'inbox_media';
const createdAtSafe = safePart(String(j.created_at_iso || new Date().toISOString()).replace(/[:.]/g, '-'));
const messageKey = safePart(
  j.provider_message_id ||
  media.wa_media_id ||
  media.url ||
  `${Date.now()}-${Math.random().toString(36).slice(2, 10)}`
);

const media_path = [
  safePart(j.org_id),
  safePart(j.conversation_id),
  `${createdAtSafe}_${safePart(j.platform)}_${safePart(j.sender_external_id)}_${messageKey}.${ext}`,
].join('/');

return [{
  json: {
    ...j,
    bucket,
    ext,
    randomSuffix: Math.random().toString(36).slice(2, 10),
    media_path,
  }
}];
